import React, { useEffect, useRef, useState } from "react";
import { io } from "socket.io-client";

const socket = io("http://localhost:3001");

export default function CallWindow({ currentUser, friend, onHangUp }) {
  const localVideo = useRef();
  const remoteVideo = useRef();
  const peerConnection = useRef();
  const [inCall, setInCall] = useState(false);

  useEffect(() => {
    socket.emit("register user", currentUser.userId);

    const pc = new RTCPeerConnection();
    peerConnection.current = pc;

    navigator.mediaDevices.getUserMedia({ video: true, audio: true })
      .then(stream => {
        localVideo.current.srcObject = stream;
        stream.getTracks().forEach(track => pc.addTrack(track, stream));
        setInCall(true);
      });

    pc.ontrack = event => {
      remoteVideo.current.srcObject = event.streams[0];
    };

    pc.onicecandidate = event => {
      if (event.candidate) {
        socket.emit("ice candidate", { toId: friend.userId, candidate: event.candidate });
      }
    };

    socket.on("incoming call", async ({ fromId, offer }) => {
      if (fromId === friend.userId) {
        await pc.setRemoteDescription(new RTCSessionDescription(offer));
        const answer = await pc.createAnswer();
        await pc.setLocalDescription(answer);
        socket.emit("call answer", { fromId: currentUser.userId, toId: friend.userId, answer });
      }
    });

    socket.on("call answered", async ({ fromId, answer }) => {
      if (fromId === friend.userId) {
        await pc.setRemoteDescription(new RTCSessionDescription(answer));
      }
    });

    socket.on("ice candidate", async (candidate) => {
      try {
        await pc.addIceCandidate(new RTCIceCandidate(candidate));
      } catch (err) {
        console.error("Error adding ICE candidate:", err);
      }
    });

    // Start call immediately
    const startCall = async () => {
      const offer = await pc.createOffer();
      await pc.setLocalDescription(offer);
      socket.emit("call request", { fromId: currentUser.userId, toId: friend.userId, offer });
    };

    startCall();

    return () => {
      socket.off("incoming call");
      socket.off("call answered");
      socket.off("ice candidate");
    };
  }, [currentUser, friend]);

  const hangUp = () => {
    if (peerConnection.current) peerConnection.current.close();
    if (localVideo.current) localVideo.current.srcObject = null;
    if (remoteVideo.current) remoteVideo.current.srcObject = null;
    setInCall(false);
    if (onHangUp) onHangUp();
  };

  return (
    <div style={{
      position: "fixed",
      top: 0, left: 0,
      width: "100%", height: "100%",
      backgroundColor: "#000",
      display: "flex",
      flexDirection: "column",
      justifyContent: "center",
      alignItems: "center",
      zIndex: 9999
    }}>
      <video ref={remoteVideo} autoPlay playsInline style={{ width: "100%", height: "100%", objectFit: "cover" }} />
      <video ref={localVideo} autoPlay muted playsInline style={{
        position: "absolute",
        bottom: "20px", right: "20px",
        width: "120px", height: "160px",
        borderRadius: "10px",
        border: "2px solid white"
      }} />
      {inCall && (
        <button
          onClick={hangUp}
          style={{
            position: "absolute",
            bottom: "40px",
            backgroundColor: "red",
            color: "white",
            border: "none",
            borderRadius: "50%",
            width: "60px",
            height: "60px",
            fontSize: "16px"
          }}
        >
          ❌
        </button>
      )}
    </div>
  );
}
